class TrainingDataStore:
    """Thread-safe store for community-contributed training data."""

    def __init__(self, data_folder):
        self.data_folder = data_folder
        self.metadata_file = os.path.join(data_folder, 'metadata.json')
        self.lock = Lock()
        self._load_metadata()

    def _load_metadata(self):
        if os.path.exists(self.metadata_file):
            with open(self.metadata_file, 'r') as f:
                self.metadata = json.load(f)
        else:
            self.metadata = {
                'classes': [],
                'samples': [],
                'total_samples': 0,
                'contributors': [],
                'created_at': datetime.utcnow().isoformat(),
                'last_updated': datetime.utcnow().isoformat()
            }
            self._save_metadata()

    def _save_metadata(self):
        with open(self.metadata_file, 'w') as f:
            json.dump(self.metadata, f, indent=2)

    def add_sample(self, image_path, label, contributor_id=None):
        with self.lock:
            if label not in self.metadata['classes']:
                if len(self.metadata['classes']) >= MAX_CLASSES:
                    raise ValueError(f"Maximum number of classes ({MAX_CLASSES}) reached.")
                self.metadata['classes'].append(label)

            sample_id = str(uuid.uuid4())
            sample = {
                'id': sample_id,
                'image_path': image_path,
                'label': label,
                'contributor': contributor_id or 'anonymous',
                'added_at': datetime.utcnow().isoformat(),
                'validated': False
            }
            self.metadata['samples'].append(sample)
            self.metadata['total_samples'] += 1
            self.metadata['last_updated'] = datetime.utcnow().isoformat()

            if contributor_id and contributor_id not in self.metadata['contributors']:
                self.metadata['contributors'].append(contributor_id)

            self._save_metadata()
            return sample_id

    def add_samples_from_csv(self, csv_path, image_base_dir=None, contributor_id=None):
        """Load CSV with columns: image_path, label (and optionally image data as base64)."""
        df = pd.read_csv(csv_path)
        required_cols = {'image_path', 'label'}

        if not required_cols.issubset(set(df.columns)):
            # Try alternative column names
            col_mapping = {}
            for col in df.columns:
                col_lower = col.lower().strip()
                if col_lower in ('image_path', 'filepath', 'file', 'image', 'path', 'filename'):
                    col_mapping['image_path'] = col
                elif col_lower in ('label', 'class', 'category', 'target', 'class_name'):
                    col_mapping['label'] = col

            if len(col_mapping) < 2:
                raise ValueError(
                    f"CSV must contain 'image_path' and 'label' columns. "
                    f"Found columns: {list(df.columns)}"
                )
            df = df.rename(columns={v: k for k, v in col_mapping.items()})

        sample_ids = []
        errors = []

        for idx, row in df.iterrows():
            try:
                img_path = row['image_path']
                label = str(row['label']).strip()

                if image_base_dir:
                    img_path = os.path.join(image_base_dir, img_path)

                if not os.path.isabs(img_path):
                    img_path = os.path.join(self.data_folder, img_path)

                if os.path.exists(img_path):
                    # Copy image to data folder
                    dest_filename = f"{uuid.uuid4()}_{secure_filename(os.path.basename(img_path))}"
                    dest_path = os.path.join(self.data_folder, 'images', dest_filename)
                    os.makedirs(os.path.dirname(dest_path), exist_ok=True)

                    img = Image.open(img_path).convert('RGB')
                    img = img.resize(IMG_SIZE)
                    img.save(dest_path)

                    sample_id = self.add_sample(dest_path, label, contributor_id)
                    sample_ids.append(sample_id)
                else:
                    errors.append(f"Row {idx}: Image not found at {img_path}")

            except Exception as e:
                errors.append(f"Row {idx}: {str(e)}")

        return sample_ids, errors

    def get_training_data(self):
        """Return numpy arrays of images and labels."""
        with self.lock:
            samples = self.metadata['samples']
            classes = self.metadata['classes']

        if not samples:
            return None, None, None

        images = []
        labels = []
        class_to_idx = {cls: idx for idx, cls in enumerate(classes)}

        for sample in samples:
            try:
                img_path = sample['image_path']
                if os.path.exists(img_path):
                    img = Image.open(img_path).convert('RGB')
                    img = img.resize(IMG_SIZE)
                    img_array = np.array(img, dtype=np.float32) / 255.0
                    images.append(img_array)
                    labels.append(class_to_idx[sample['label']])
            except Exception as e:
                logger.warning(f"Error loading sample {sample['id']}: {e}")

        if not images:
            return None, None, None

        return np.array(images), np.array(labels), classes

    def get_stats(self):
        with self.lock:
            class_counts = {}
            for sample in self.metadata['samples']:
                label = sample['label']
                class_counts[label] = class_counts.get(label, 0) + 1

            return {
                'total_samples': self.metadata['total_samples'],
                'num_classes': len(self.metadata['classes']),
                'classes': self.metadata['classes'],
                'class_distribution': class_counts,
                'num_contributors': len(self.metadata['contributors']),
                'last_updated': self.metadata['last_updated']
            }


class ImageClassificationModel:
    """Manages the image classification model lifecycle."""

    def __init__(self, model_folder):
        self.model_folder = model_folder
        self.model = None
        self.classes = []
        self.training_history = []
        self.lock = Lock()
        self.is_training = False
        self.model_version = 0
        self._load_latest_model()

    def _load_latest_model(self):
        model_path = os.path.join(self.model_folder, 'latest_model')
        meta_path = os.path.join(self.model_folder, 'model_meta.json')

        if os.path.exists(model_path) and os.path.exists(meta_path):
            try:
                self.model = keras.models.load_model(model_path)
                with open(meta_path, 'r') as f:
                    meta = json.load(f)
                self.classes = meta.get('classes', [])
                self.model_version = meta.get('version', 0)
                logger.info(f"Loaded model version {self.model_version} with {len(self.classes)} classes")
            except Exception as e:
                logger.warning(f"Could not load existing model: {e}")
                self.model = None

    def _build_model(self, num_classes, input_shape=(64, 64, 3)):
        """Build a CNN model for image classification."""
        model = keras.Sequential([
            layers.Input(shape=input_shape),

            # Data augmentation layers
            layers.RandomFlip("horizontal"),
            layers.RandomRotation(0.1),
            layers.RandomZoom(0.1),

            # Conv Block 1
            layers.Conv2D(32, (3, 3), padding='same'),
            layers.BatchNormalization(),
            layers.Activation('relu'),
            layers.Conv2D(32, (3, 3), padding='same'),
            layers.BatchNormalization(),
            layers.Activation('relu'),
            layers.MaxPooling2D((2, 2)),
            layers.Dropout(0.25),

            # Conv Block 2
            layers.Conv2D(64, (3, 3), padding='same'),
            layers.BatchNormalization(),
            layers.Activation('relu'),
            layers.Conv2D(64, (3, 3), padding='same'),
            layers.BatchNormalization(),
            layers.Activation('relu'),
            layers.MaxPooling2D((2, 2)),
            layers.Dropout(0.25),

            # Conv Block 3
            layers.Conv2D(128, (3, 3), padding='same'),
            layers.BatchNormalization(),
            layers.Activation('relu'),
            layers.Conv2D(128, (3, 3), padding='same'),
            layers.BatchNormalization(),
            layers.Activation('relu'),
            layers.MaxPooling2D((2, 2)),
            layers.Dropout(0.25),

            # Dense layers
            layers.Flatten(),
            layers.Dense(256),
            layers.BatchNormalization(),
            layers.Activation('relu'),
            layers.Dropout(0.5),
            layers.Dense(num_classes, activation='softmax')
        ])

        model.compile(
            optimizer=keras.optimizers.Adam(learning_rate=0.001),
            loss='sparse_categorical_crossentropy',
            metrics=['accuracy']
        )

        return model

    def train(self, images, labels, classes, epochs=20, batch_size=32, validation_split=0.2):
        """Train the model on provided data."""
        with self.lock:
            if self.is_training:
                return {'error': 'Training already in progress'}
            self.is_training = True

        try:
            num_classes = len(classes)
            logger.info(f"Starting training with {len(images)} samples, {num_classes} classes, {epochs} epochs")

            # Build or rebuild model if class count changed
            if self.model is None or len(self.classes) != num_classes:
                self.model = self._build_model(num_classes, input_shape=images.shape[1:])
                logger.info("Built new model")
            else:
                logger.info("Continuing training on existing model")

            self.classes = classes

            # Callbacks
            callbacks = [
                keras.callbacks.EarlyStopping(
                    monitor='val_loss',
                    patience=5,
                    restore_best_weights=True,
                    verbose=1
                ),
                keras.callbacks.ReduceLROnPlateau(
                    monitor='val_loss',
                    factor=0.5,
                    patience=3,
                    min_lr=1e-6,
                    verbose=1
                )
            ]

            # Shuffle data
            indices = np.random.permutation(len(images))
            images = images[indices]
            labels = labels[indices]

            # Train
            history = self.model.fit(
                images, labels,
                epochs=epochs,
                batch_size=batch_size,
                validation_split=validation_split,
                callbacks=callbacks,
                verbose=1
            )

            # Save model
            self.model_version += 1
            model_path = os.path.join(self.model_folder, 'latest_model')
            self.model.save(model_path)

            # Save versioned copy
            versioned_path = os.path.join(self.model_folder, f'model_v{self.model_version}')
            self.model.save(versioned_path)

            # Save metadata
            meta = {
                'classes': list(classes),
                'version': self.model_version,
                'trained_at': datetime.utcnow().isoformat(),
                'num_samples': len(images),
                'epochs_completed': len(history.history['loss']),
                'final_loss': float(history.history['loss'][-1]),
                'final_accuracy': float(history.history['accuracy'][-1]),
                'final_val_loss': float(history.history['val_loss'][-1]) if 'val_loss' in history.history else None,
                'final_val_accuracy': float(history.history['val_accuracy'][-1]) if 'val_accuracy' in history.history else None,
            }

            with open(os.path.join(self.model_folder, 'model_meta.json'), 'w') as f:
                json.dump(meta, f, indent=2)

            training_result = {
                'model_version': self.model_version,
                'epochs_completed': len(history.history['loss']),
                'final_loss': float(history.history['loss'][-1]),
                'final_accuracy': float(history.history['accuracy'][-1]),
                'final_val_loss': float(history.history['val_loss'][-1]) if 'val_loss' in history.history else None,
                'final_val_accuracy': float(history.history['val_accuracy'][-1]) if 'val_accuracy' in history.history else None,
                'num_samples': len(images),
                'num_classes': num_classes,
                'classes': list(classes)
            }

            self.training_history.append(training_result)
            logger.info(f"Training complete. Model v{self.model_version}")

            return training_result

        except Exception as e:
            logger.error(f"Training error: {e}")
            return {'error': str(e)}

        finally:
            with self.lock:
                self.is_training = False

    def predict(self, image):
        """Predict class for a single image."""
        if self.model is None:
            return {'error': 'No trained model available'}

        if isinstance(image, Image.Image):
            image = image.convert('RGB').resize(IMG_SIZE)
            image = np.array(image, dtype=np.float32) / 255.0

        if image.ndim == 3:
            image = np.expand_dims(image, axis=0)

        predictions = self.model.predict(image, verbose=0)
        predicted_idx = np.argmax(predictions[0])
        confidence = float(predictions[0][predicted_idx])

        # Get top-k predictions
        top_k = min(5, len(self.classes))
        top_indices = np.argsort(predictions[0])[::-1][:top_k]

        top_predictions = [
            {
                'class': self.classes[idx],
                'confidence': float(predictions[0][idx])
            }
            for idx in top_indices
        ]

        return {
            'predicted_class': self.classes[predicted_idx],
            'confidence': confidence,
            'top_predictions': top_predictions,
            'model_version': self.model_version
        }

    def get_status(self):
        return {
            'model_loaded': self.model is not None,
            'model_version': self.model_version,
            'num_classes': len(self.classes),
            'classes': self.classes,
            'is_training': self.is_training,
            'training_history_count': len(self.training_history)
        }


# Initialize global instances
data_store = TrainingDataStore(DATA_FOLDER)
model_manager = ImageClassificationModel(MODEL_FOLDER)


def allowed_file(filename, allowed_extensions):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in allowed_extensions


